/**
 * Проверяет, является ли контент fallback-ом
 */
export function isFallbackContent(content: string): boolean {
  return content.includes('Автоматическая генерация временно недоступна') ||
         content.includes('будет автоматически обновлён при следующем посещении')
}

    })
  } catch (error) {
    console.error('[Stream] Error:', error)
    return new Response('Internal server error', { status: 500 })
  }
}

/**
 * Строит domain-specific системный промпт.
 * Объединяет базовый SYSTEM_PROMPTS.theory с domain-specific инструкциями.
 */
function buildDomainSystemPrompt(domain: Domain): string {
  const basePrompt = SYSTEM_PROMPTS.theory

  // Пробуем получить domain-specific промпт
  try {
    const domainPrompt = getDomainPrompt(domain)
    if (domainPrompt && domainPrompt.systemPrompt) {
      return `${basePrompt}\n\n═══════════════════════════════════════════════════════════════
🔬 DOMAIN-SPECIFIC ИНСТРУКЦИИ (${domain}):
═══════════════════════════════════════════════════════════════
${domainPrompt.systemPrompt}

${domainPrompt.exampleContent ? `ПРИМЕР ЭТАЛОННОГО КОНТЕНТА:\n${domainPrompt.exampleContent.slice(0, 1000)}` : ''}`
    }
  } catch (e) {
    console.warn(`[Stream] Failed to get domain prompt for ${domain}:`, e)
  }

  return basePrompt
}

function getStreamingTheoryPrompt(topicName: string, courseTitle: string, context: string, domain: Domain): string {
  const domainHints: Record<Domain, string> = {
    PROGRAMMING: 'Включи рабочие примеры кода с комментариями, паттерны и антипаттерны.',
    MATHEMATICS: 'Формулы в LaTeX, пошаговые выводы, геометрическая интуиция.',
    PHYSICS: 'Формулы в LaTeX, физическая интуиция, мысленные эксперименты, единицы СИ.',
    CHEMISTRY: 'Уравнения реакций, молекулярные структуры, практические примеры.',
    BIOLOGY: 'Схемы процессов, классификации, сравнительные таблицы.',
    HISTORY: 'Даты, причинно-следственные связи, исторический контекст.',
    LANGUAGES: 'Примеры использования, грамматические правила, сравнения.',
    ECONOMICS: 'Графики, формулы, экономические модели, реальные данные.',
